import requests

KONG_ADMIN_URL = 'http://localhost:8001'

# Function to create a service
def create_service(service_name, url):
    service_data = {
        'name': service_name,
        'url': url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services', json=service_data)
    return response.json()

# Function to create a route
def create_route(service_name, paths):
    route_data = {
        'paths': paths,
        'service': {'name': service_name}
    }
    response = requests.post(f'{KONG_ADMIN_URL}/routes', json=route_data)
    return response.json()

# Function to create an upstream target
def create_upstream(upstream_name, targets):
    upstream_data = {
        'name': upstream_name
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json=upstream_data)
    if response.status_code == 201:
        for target in targets:
            target_data = {
                'target': target,
                'weight': 100
            }
            requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets', json=target_data)
    return response.json()

# Example usage
